fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let mix = required_f32(params, "mix").map_err(anyhow::Error::msg)?;
    let drive = required_f32(params, "drive").map_err(anyhow::Error::msg)?;
    let blend = required_f32(params, "blend").map_err(anyhow::Error::msg)?;
    let lp_pre_freq = required_f32(params, "lp_pre_freq").map_err(anyhow::Error::msg)?;
    let hp_pre_freq = required_f32(params, "hp_pre_freq").map_err(anyhow::Error::msg)?;
    let lp_post_freq = required_f32(params, "lp_post_freq").map_err(anyhow::Error::msg)?;
    let hp_post_freq = required_f32(params, "hp_post_freq").map_err(anyhow::Error::msg)?;
    let p_freq = required_f32(params, "p_freq").map_err(anyhow::Error::msg)?;
    let p_level = required_f32(params, "p_level").map_err(anyhow::Error::msg)?;
    let p_q = required_f32(params, "p_q").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_LEVEL_OUT, level_out),
        (PORT_CTRL_MIX, mix),
        (PORT_CTRL_DRIVE, drive),
        (PORT_CTRL_BLEND, blend),
        (PORT_CTRL_LP_PRE_FREQ, lp_pre_freq),
        (PORT_CTRL_HP_PRE_FREQ, hp_pre_freq),
        (PORT_CTRL_LP_POST_FREQ, lp_post_freq),
        (PORT_CTRL_HP_POST_FREQ, hp_post_freq),
        (PORT_CTRL_P_FREQ, p_freq),
        (PORT_CTRL_P_LEVEL, p_level),
        (PORT_CTRL_P_Q, p_q),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

